1	// Package s3 provides a WAF bundle fetcher for PLM's S3-compatible storage (SeaweedFS).
2	package s3
3	
4	import (
5		"context"
6		"crypto/sha256"
7		"crypto/tls"
8		"crypto/x509"
9		"encoding/hex"
10		"errors"
11		"fmt"
12		"io"
13		"net/http"
14		"strings"
15	
16		"github.com/aws/aws-sdk-go-v2/aws"
17		awsconfig "github.com/aws/aws-sdk-go-v2/config"
18		"github.com/aws/aws-sdk-go-v2/credentials"
19		"github.com/aws/aws-sdk-go-v2/service/s3"
20		"github.com/go-logr/logr"
21	
22		sharedsecrets "github.com/nginx/nginx-gateway-fabric/v2/internal/controller/state/graph/shared/secrets"
23	)
24	
25	// Credentials holds S3 auth credentials resolved from Kubernetes Secrets.
26	type Credentials struct {
27		// AccessKeyID is the S3 access key ID.
28		AccessKeyID string
29		// SecretAccessKey is the S3 secret access key.
30		SecretAccessKey string
31	}
32	
33	// TLSConfig holds TLS configuration resolved from Kubernetes Secrets.
34	type TLSConfig struct {
35		// CAData is the PEM-encoded CA certificate for verifying the S3 endpoint.
36		CAData []byte
37		// CertData is the PEM-encoded client certificate for mutual TLS.
38		CertData []byte
39		// KeyData is the PEM-encoded client private key for mutual TLS.
40		KeyData []byte
41	}
42	
43	// Fetcher downloads WAF bundles from PLM's S3-compatible storage (SeaweedFS).
44	type Fetcher struct {
45		logger     logr.Logger
46		endpoint   string
47		skipVerify bool
48	}
49	
50	// NewFetcher creates a new S3 fetcher for the given endpoint.
51	// The endpoint and skipVerify are fixed at startup from CLI flags.
52	func NewFetcher(logger logr.Logger, endpoint string, skipVerify bool) *Fetcher {
53		return &Fetcher{
54			logger:     logger,
55			endpoint:   endpoint,
56			skipVerify: skipVerify,
57		}
58	}
59	
60	// FetchBundle downloads a bundle from the given S3 location and verifies its SHA-256 checksum.
61	// A new S3 client is constructed per call with the provided credentials and TLS config
62	// (fetches are infrequent and event-driven, so client caching is unnecessary).
63	// The location must be an s3:// URI (e.g. "s3://bucket/path/bundle.tgz").
64	// creds may be nil for anonymous access; tlsCfg may be nil to use system CAs.
65	func (f *Fetcher) FetchBundle(
66		ctx context.Context,
67		location string,
68		expectedSHA256 string,
69		creds *Credentials,
70		tlsCfg *TLSConfig,
71	) ([]byte, error) {
72		bucket, key, err := parseS3URI(location)
73		if err != nil {
74			return nil, fmt.Errorf("invalid S3 location: %w", err)
75		}
76	
77		client, err := f.buildClient(ctx, creds, tlsCfg)
78		if err != nil {
79			return nil, fmt.Errorf("failed to build S3 client: %w", err)
80		}
81	
82		f.logger.V(1).Info(
83			"Fetching PLM bundle from S3",
84			"bucket", bucket,
85			"key", key,
86		)
87	
88		result, err := client.GetObject(ctx, &s3.GetObjectInput{
89			Bucket: aws.String(bucket),
90			Key:    aws.String(key),
91		})
92		if err != nil {
93			return nil, fmt.Errorf("S3 GetObject failed for %s: %w", location, err)
94		}
95		defer result.Body.Close()
96	
97		data, err := io.ReadAll(result.Body)
98		if err != nil {
99			return nil, fmt.Errorf("failed to read S3 object body: %w", err)
100		}
101	
102		if expectedSHA256 != "" {
103			actualHash := sha256.Sum256(data)
104			actualHex := hex.EncodeToString(actualHash[:])
105			if !strings.EqualFold(actualHex, expectedSHA256) {
106				return nil, fmt.Errorf(
107					"SHA-256 mismatch for %s: expected %s, got %s",
108					location,
109					expectedSHA256,
110					actualHex,
111				)
112			}
113		}
114	
115		f.logger.V(1).Info(
116			"Successfully fetched PLM bundle",
117			"bucket", bucket,
118			"key", key,
119			"size", len(data),
120		)
121	
122		return data, nil
123	}
124	
125	// parseS3URI parses an s3://bucket/key URI into bucket and key components.
126	func parseS3URI(uri string) (bucket, key string, err error) {
127		if uri == "" {
128			return "", "", fmt.Errorf("empty S3 URI")
129		}
130	
131		if !strings.HasPrefix(uri, "s3://") {
132			return "", "", fmt.Errorf("URI must start with s3://: %s", uri)
133		}
134	
135		path := strings.TrimPrefix(uri, "s3://")
136		if path == "" {
137			return "", "", fmt.Errorf("missing bucket in S3 URI: %s", uri)
138		}
139	
140		slashIdx := strings.IndexByte(path, '/')
141		if slashIdx < 0 || slashIdx == len(path)-1 {
142			return "", "", fmt.Errorf("missing key in S3 URI: %s", uri)
143		}
144	
145		bucket = path[:slashIdx]
146		key = path[slashIdx+1:]
147	
148		if bucket == "" {
149			return "", "", fmt.Errorf("empty bucket in S3 URI: %s", uri)
150		}
151	
152		if key == "" {
153			return "", "", fmt.Errorf("empty key in S3 URI: %s", uri)
154		}
155	
156		return bucket, key, nil
157	}
158	
159	// buildClient creates a new S3 client with the provided credentials and TLS configuration.
160	func (f *Fetcher) buildClient(
161		ctx context.Context,
162		creds *Credentials,
163		tlsCfg *TLSConfig,
164	) (*s3.Client, error) {
165		// Validate the fully assembled TLS config at the fetcher boundary. Secret resolution only
166		// checks Secret shape/presence so it can log which Kubernetes Secret is misconfigured.
167		if err := validateTLSConfig(tlsCfg); err != nil {
168			return nil, fmt.Errorf("invalid TLS configuration: %w", err)
169		}
170	
171		var opts []func(*awsconfig.LoadOptions) error
172	
173		// Set credentials
174		if creds != nil && creds.AccessKeyID != "" {
175			opts = append(opts, awsconfig.WithCredentialsProvider(
176				credentials.NewStaticCredentialsProvider(
177					creds.AccessKeyID,
178					creds.SecretAccessKey,
179					"",
180				),
181			))
182		} else {
183			opts = append(opts, awsconfig.WithCredentialsProvider(aws.AnonymousCredentials{}))
184		}
185	
186		// Build TLS config
187		transport, err := buildTLSTransport(tlsCfg, f.skipVerify)
188		if err != nil {
189			return nil, fmt.Errorf("failed to build TLS transport: %w", err)
190		}
191		if transport != nil {
192			opts = append(opts, awsconfig.WithHTTPClient(&http.Client{
193				Transport: transport,
194			}))
195		}
196	
197		// Use a dummy region since SeaweedFS doesn't care about regions
198		opts = append(opts, awsconfig.WithRegion("us-east-1"))
199	
200		cfg, err := awsconfig.LoadDefaultConfig(ctx, opts...)
201		if err != nil {
202			return nil, fmt.Errorf("failed to load AWS config: %w", err)
203		}
204	
205		client := s3.NewFromConfig(cfg, func(o *s3.Options) {
206			o.BaseEndpoint = aws.String(f.endpoint)
207			o.UsePathStyle = true // Required for SeaweedFS
208		})
209	
210		return client, nil
211	}
212	
213	// buildTLSTransport creates an HTTP transport with custom TLS configuration.
214	// It clones http.DefaultTransport to preserve default proxy/timeout/connection-reuse settings
215	// and appends any custom CA to the system cert pool.
216	// Returns (nil, nil) if no custom TLS is needed.
217	func buildTLSTransport(tlsCfg *TLSConfig, skipVerify bool) (*http.Transport, error) {
218		if tlsCfg == nil && !skipVerify {
219			return nil, nil //nolint:nilnil // nil transport means "use default", not an error
220		}
221	
222		defaultTransport, ok := http.DefaultTransport.(*http.Transport)
223		if !ok {
224			return nil, fmt.Errorf("http.DefaultTransport is not *http.Transport")
225		}
226		transport := defaultTransport.Clone()
227		transport.TLSClientConfig = &tls.Config{
228			MinVersion:         tls.VersionTLS12,
229			InsecureSkipVerify: skipVerify, //nolint:gosec // controlled by CLI flag
230		}
231	
232		if tlsCfg != nil {
233			if len(tlsCfg.CAData) > 0 {
234				pool, err := x509.SystemCertPool()
235				if err != nil {
236					pool = x509.NewCertPool()
237				}
238				if !pool.AppendCertsFromPEM(tlsCfg.CAData) {
239					return nil, fmt.Errorf("failed to append CA certificate to pool")
240				}
241				transport.TLSClientConfig.RootCAs = pool
242			}
243	
244			if len(tlsCfg.CertData) > 0 && len(tlsCfg.KeyData) > 0 {
245				cert, err := tls.X509KeyPair(tlsCfg.CertData, tlsCfg.KeyData)
246				if err != nil {
247					return nil, fmt.Errorf("failed to load client TLS key pair: %w", err)
248				}
249				transport.TLSClientConfig.Certificates = []tls.Certificate{cert}
250			}
251		}
252	
253		return transport, nil
254	}
255	
256	func validateTLSConfig(tlsCfg *TLSConfig) error {
257		// This validates TLS semantics for the assembled client config. It intentionally does not
258		// know about individual Kubernetes Secrets; that context is handled during secret resolution.
259		if tlsCfg == nil {
260			return nil
